import{_ as t,o,c as a,a3 as d}from"./chunks/framework.BveOjhN0.js";const u=JSON.parse('{"title":"Tenant Settings — Developer Guide","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Tenant Settings — Developer Guide | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/developer-guide/tenant-settings"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Tenant Settings — Developer Guide | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/developer-guide/tenant-settings"}]]},"headers":[],"relativePath":"developer-guide/tenant-settings.md","filePath":"developer-guide/tenant-settings.md","lastUpdated":1784586025000}'),n={name:"developer-guide/tenant-settings.md"};function i(c,e,r,s,l,p){return o(),a("div",null,[...e[0]||(e[0]=[d('<h1 id="tenant-settings-—-developer-guide" tabindex="-1">Tenant Settings — Developer Guide <a class="header-anchor" href="#tenant-settings-—-developer-guide" aria-label="Permalink to &quot;Tenant Settings — Developer Guide&quot;">​</a></h1><h2 id="core-types" tabindex="-1">Core types <a class="header-anchor" href="#core-types" aria-label="Permalink to &quot;Core types&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Piece</th><th>Role</th></tr></thead><tbody><tr><td><code>App\\Support\\TenantSettingDefinitions</code></td><td>Catalog of overridable keys + sensitive keys</td></tr><tr><td><code>App\\Services\\Tenant\\TenantSettingService</code></td><td>Hierarchy resolver, cache, branding uploads, runtime mail/config, public bootstrap</td></tr><tr><td><code>App\\Services\\Storage\\FileUploadService</code></td><td>Disk-agnostic store/replace/delete/url (shared with Central)</td></tr><tr><td><code>TenantSettingController</code></td><td>Authenticated list/update, test-mail, branding upload</td></tr><tr><td><code>PublicSettingsController</code> (tenant)</td><td><code>GET /api/tenant/v1/public/settings</code> — resolved payload, no secrets</td></tr><tr><td><code>InitializeTenancy</code></td><td>After tenancy init, calls <code>TenantSettingService::applyRuntimeConfig()</code></td></tr></tbody></table><h2 id="hierarchy" tabindex="-1">Hierarchy <a class="header-anchor" href="#hierarchy" aria-label="Permalink to &quot;Hierarchy&quot;">​</a></h2><p><code>TenantSettingService::resolve($key)</code> returns <code>{ value, source }</code> where <code>source</code> is one of:</p><ul><li><code>tenant</code> — row in <code>tenant_settings</code></li><li><code>workspace</code> — Tenant model column (<code>workspace_name</code>, <code>company_name</code>, <code>timezone</code>, …)</li><li><code>central</code> — <code>SystemSettingService</code></li><li><code>system</code> — hard-coded / config fallback</li></ul><p>Business code must call the service (<code>applicationName()</code>, <code>logoUrl()</code>, <code>supportEmail()</code>, <code>buttonColor()</code>, <code>usesCustomMailProvider()</code>, …) instead of branching on raw settings.</p><h2 id="mail-provider" tabindex="-1">Mail provider <a class="header-anchor" href="#mail-provider" aria-label="Permalink to &quot;Mail provider&quot;">​</a></h2><p><code>mail_mode</code> is <code>system</code> (inherit Central via <code>EmailManager</code>) or <code>custom</code> (tenant provider: SMTP / Postmark / Mailgun / …).</p><p><code>usesCustomMailProvider()</code> is true when <code>mail_mode=custom</code>, or (legacy) when <code>mail_host</code> is filled and <code>mail_mode</code> is unset. Backfill with <code>php artisan email:migrate-tenant-mail-modes</code>.</p><p>Queued mail re-applies config via <code>ApplyEmailRuntimeConfig</code> on the <code>emails</code> queue.</p><p>Secrets are encrypted with <code>Crypt</code> and masked as <code>********</code> in the admin API.</p><h2 id="admin-api" tabindex="-1">Admin API <a class="header-anchor" href="#admin-api" aria-label="Permalink to &quot;Admin API&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Notes</th></tr></thead><tbody><tr><td>GET</td><td><code>/api/tenant/v1/settings</code></td><td>Resolved values + <code>source</code> / <code>is_overridden</code></td></tr><tr><td>PUT</td><td><code>/api/tenant/v1/settings</code></td><td><code>{ &quot;settings&quot;: { &quot;key&quot;: value } }</code></td></tr><tr><td>POST</td><td><code>/api/tenant/v1/settings/test-mail</code></td><td><code>{ &quot;email&quot;: &quot;…&quot;, &quot;settings&quot;?: {…} }</code> — structured result</td></tr><tr><td>POST</td><td><code>/api/tenant/v1/settings/branding/{logo|favicon}</code></td><td>Multipart <code>file</code> → <code>FileUploadService</code> under <code>tenants/{uuid}/branding/…</code></td></tr><tr><td>GET</td><td><code>/api/tenant/v1/email-logs</code></td><td>Workspace-scoped delivery logs</td></tr><tr><td>GET</td><td><code>/api/tenant/v1/email-logs/{uuid}</code></td><td>Show one log</td></tr></tbody></table><p>Permissions (<code>config/tenant-permissions.php</code>): <code>settings.list</code>, <code>settings.update</code>, <code>email-logs.list</code>, <code>email-logs.view</code>.</p><p>Object storage: <a href="/developer-guide/object-storage">object-storage.md</a>.</p><p>Requires tenancy (<code>X-Tenant-Domain</code> / domain) + <code>auth:tenant-api</code>.</p><h2 id="public-api" tabindex="-1">Public API <a class="header-anchor" href="#public-api" aria-label="Permalink to &quot;Public API&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Notes</th></tr></thead><tbody><tr><td>GET</td><td><code>/api/tenant/v1/public/settings</code></td><td>Resolved branding + Central-inherited maintenance/password/session</td></tr></tbody></table><h2 id="frontend" tabindex="-1">Frontend <a class="header-anchor" href="#frontend" aria-label="Permalink to &quot;Frontend&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Piece</th><th>Role</th></tr></thead><tbody><tr><td><code>TenantSettingsPage</code></td><td><code>/settings</code> — General / Branding / Mail</td></tr><tr><td><code>tenantSettingService</code></td><td>Tenant API client</td></tr><tr><td><code>useSettingsStore</code></td><td>Tenant public bootstrap when a workspace domain is known; otherwise Central</td></tr></tbody></table><h2 id="schema" tabindex="-1">Schema <a class="header-anchor" href="#schema" aria-label="Permalink to &quot;Schema&quot;">​</a></h2><p><code>tenant_settings</code>: <code>tenant_id</code>, <code>key</code>, <code>value</code>, <code>type</code>, <code>group</code>, unique <code>(tenant_id, key)</code>.</p><p>Profile sync: saving <code>company_name</code>, <code>timezone</code>, <code>locale</code>, <code>currency</code>, <code>logo_path</code> also updates the <code>tenants</code> row. <code>workspace_name</code> is stored on the tenant (not as a KV override of Central).</p><h2 id="tests" tabindex="-1">Tests <a class="header-anchor" href="#tests" aria-label="Permalink to &quot;Tests&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --compact</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tests/Feature/Tenant/Settings/</span></span></code></pre></div><p>Playwright: <code>npm run test:e2e:tenant-settings</code> in <code>SaaS-Frontend</code>.</p>',27)])])}const m=t(n,[["render",i]]);export{u as __pageData,m as default};
